var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"느, 늑대…….","JPN":"お、狼……","ENG":"W-wolf…","TWN":"狼……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"넌…… 저주받은 늑대인가……?","JPN":"お前は……呪われた狼か……？","ENG":"Are you… the Cursed Wolf…?","TWN":"你……就是受到詛咒的狼……？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"널…… 찾고 있었다…… 아주 오랫동안……","JPN":"お前を……探していた……長い間……","ENG":"I've been… looking for you… for a very long time…","TWN":"我……找你…… 找了好久……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"나락의 바닥에서…… 끝없는 고통에 시달리며……","JPN":"奈落の底で……果てのない苦痛を味わい……","ENG":"Writhing in eternal agony… at the bottom of the abyss…","TWN":"我在地獄……受到無止盡的痛苦……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"네게 복수할 날만을……!","JPN":"お前に復讐する日だけを……！","ENG":"Counting the days until I take revenge on you…!","TWN":"我要向你報仇……！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"지난번에 마주친 그 녀석도 그렇고…….","JPN":"この前会ったやつもそうだし……","ENG":"Hmm, you're just like the guy from last time…","TWN":"上次交手的那個傢伙也是……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"너희들이 왜 나를 찾는 건지, 왜 내게 그렇게 증오를 불태우는 건지 잘 모르겠어.","JPN":"あなたたちがなぜ私を探しているのか、なぜ私をそんなに憎んでいるのかはわからない。","ENG":"Look, I don't know what you want from me or why you hate me so much.","TWN":"你們到底有什麼毛病？為什麼要找我？為什麼那麼痛恨我？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어쩌면 내가 모르는 기억들 중에 그럴 만한 이유가 있을지도 모르지.","JPN":"もしかしたら私の知らない記憶の中に、その理由があるかもしれない。","ENG":"Maybe you have a pretty good reason in those memories I can't recollect.","TWN":"或許在我不知道的記憶中可能會有答案，"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 지금 난 선배를 구출하러 온 거야.","JPN":"でも今の私は先輩を助けに来たの。","ENG":"But right now, I'm here to rescue Shiyoon.","TWN":"但現在，我是來救前輩的！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까…… 여기서 네 한탄이나 들어 주고 있을 시간은 없어!","JPN":"だから……ここであなたの愚痴を聞いてやる時間なんかない！","ENG":"So I don't have time to sit around and listen to you vent!","TWN":"所以……我沒那個時間聽你廢話！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"크하아아악!!","JPN":"ぐあああああっ！！","ENG":"Graah!!","TWN":"呃啊啊啊啊！！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_21"},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"피가……! 더 많은 용의 피가 필요해……!","JPN":"血が……！　もっと多くの龍の血が必要だ……！","ENG":"Blood…! Need more Dragon Blood…!","TWN":"血……！我要更多龍血……！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"진정한 용이 되려면…… 더 많은 피가……!","JPN":"真の龍になるためには……多くの血が……！","ENG":"Need more blood… to become the true Dragon…!","TWN":"還要更多血……才能成為真正的龍……！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 녀석, 대체 뭐야? 약해질 기미가 안 보이잖아?","JPN":"こいつ、どうなってるの？　全然弱まらないじゃん！","ENG":"What the heck is this thing? It's not getting any weaker!","TWN":"這傢伙怎麼回事？怎麼完全沒有變弱的感覺？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양! 조심하세요!","JPN":"ミナさん！　気をつけてください！","ENG":"Mina! Watch out!","TWN":"米娜，小心！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"제길, 아직도 이런 힘이……!","JPN":"ちっ、まだそんな力が……！","ENG":"Damn it, how's it still so strong?!","TWN":"可惡，竟然還這麼能打……！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"<color=#ff3636>시윤아? 거기 있었구나!</color>","JPN":"<color=#ff3636>シリュウ！　そこにいたのね！</color>","ENG":"<color=#ff3636>Shiyoon? There you are!</color>","TWN":"<color=#ff3636>時雲？原來你在這裡。</color>"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"<color=#ff3636>널 보고 싶었단다!</color>","JPN":"<color=#ff3636>あなたに会いたかったのよ！</color>","ENG":"<color=#ff3636>Oh, I've missed you so much, sweetie!</color>","TWN":"<color=#ff3636>媽媽好想你！</color>"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"크윽?!!","JPN":"くうっ……！？","ENG":"Huh?!!","TWN":"唔？！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"<color=#ff3636>엄마가…… 네 피가 조금, 아니, 많이 필요하단다.</color>","JPN":"<color=#ff3636>お母さんね……あなたの血が少し、いえ、たくさん必要なの。</color>","ENG":"<color=#ff3636>Mommy needs… a little, no, a lot of your blood.</color>","TWN":"<color=#ff3636>媽媽……需要一些，不是很多你的血。</color>"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 그 목소리…….","JPN":"待ってください、その声は……","ENG":"Wait, that voice…","TWN":"你的聲音……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"<color=#ff3636>그러니까…… 줄 수 있지?</color>","JPN":"<color=#ff3636>だから……くれるわよね？</color>","ENG":"<color=#ff3636>So can you… give it to mommy?</color>","TWN":"<color=#ff3636>你可以……把血給媽媽嗎？</color>"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"<color=#ff3636>넌 착한 아이잖니, 시윤아?</color>","JPN":"<color=#ff3636>あなたはイイ子だものね、シリュウ。</color>","ENG":"<color=#ff3636>You're a good boy, aren't you Shiyoon?</color>","TWN":"<color=#ff3636>時雲你一向很乖的呀？</color>"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"<color=#ff3636>네 피를…… 모두 내놔!</color>","JPN":"<color=#ff3636>お前の血を……全て寄こせ！</color>","ENG":"<color=#ff3636>Give me... all your blood!</color>","TWN":"<color=#ff3636>把你的血……交出來！</color>"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배한테서 떨어져!!","JPN":"先輩から離れろ！！","ENG":"Get away from him!!","TWN":"你給我離前輩遠一點！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"허억…… 허억……","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배, 괜찮아? 방금 저 녀석이 뭐라고 한 거야?","JPN":"先輩、大丈夫？　さっきあいつになんて言われたの？","ENG":"You okay, Shiyoon? What the heck did that thing say just now?","TWN":"前輩你還好嗎？剛才那傢伙跟你說什麼？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"괜찮다고 말하고 싶지만……. 몰골이 그렇지 않네요.","JPN":"大丈夫と言いたいところですが……そう言い切れませんね。","ENG":"I wish I could say I'm fine… But it's pretty obvious I'm not.","TWN":"我很想說我還好……但我很明顯不好。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마도……. 피해를 입으면 제 피를 강제로 흡수하는 것 같아요.","JPN":"おそらく……ダメージを受けると僕の血を強制的に吸収するみたいです。","ENG":"It seems like… that thing absorbs my blood whenever it takes damage.","TWN":"應該是……我受傷的話，他就可以強行吸我的血。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"피를 흡수해?","JPN":"血を吸収する？","ENG":"Absorbs your blood?","TWN":"吸血？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"갇혀 있을 때도 피를 뽑혔다고 했잖아. 정말 위험한 거 아냐?","JPN":"閉じ込められた時も血を抜かれたと言ってたよね。本当に危ない状態なんじゃないの？","ENG":"But you said they took your blood back there. Isn't this really dangerous?","TWN":"你被關起來的時候不是也有被抽血嗎？那這樣很危險欸！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러게 말이죠. 하하…… 빈혈이라도 생기면 곤란한데…….","JPN":"そうですね。ハハ……貧血にでもなったら困りますが……","ENG":"I guess, so. Haha… I hope I don't get anemic…","TWN":"是呀，呵呵……害我貧血的話怎麼辦……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 죄송하지만…… 잠시 쉬고 있을게요.","JPN":"ミナさん、悪いけど……ちょっと休みますね。","ENG":"I'm sorry, Mina… but I need to rest for a bit.","TWN":"米娜，抱歉……我需要休息一下。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그, 그래! 걱정 마! 내가 금방 해치울게!","JPN":"い、いいよ！　心配しないで！　私がすぐ倒すから！","ENG":"S-sure thing! Don't worry! I'll get rid of that thing right away!","TWN":"喔，好！你放心，我很快就把他們處理掉！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"잠깐. 저 녀석, 그러면 또 선배의 피를 흡수할 텐데…….","JPN":"待って、そうするとあいつがまた先輩の血を吸収してしまう……","ENG":"Hang on. If I do that, it'll just absorb his blood again…","TWN":"等等，萬一他趁我不在又吸前輩的血怎麼辦……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"크윽……!! 어, 어떡하지?","JPN":"くっ……！！　ど、どうすればいいの？","ENG":"Hngh!! W-what should I do?","TWN":"唔……！怎麼辦？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"방법이 있을 거야! 분명 무슨 방법이……!","JPN":"何か方法があるはず……きっと……！","ENG":"There's got to be a way! But what…?!","TWN":"一定有辦法的！有什麼辦法……！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭……?!","JPN":"くっ……！？","ENG":"Ugh…?!","TWN":"唔……？！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};